const files = $input.all();

const decoded = [];
for (let i = 0; i < files.length; i++) {
  const name = files[i].binary.data.fileName.replace('.html', '');
  const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
  const content = buffer.toString('utf8');
  decoded.push({ json: { name, html: content } });
}

return decoded;

const template_parts = {};
$input.all().forEach(file => {
  const name = file.json.name;
  const html = file.json.html;
  template_parts[name] = html;
});

return [
  {
    json: {
      template_parts
    }
  }
];

const templates = $('Merge Templates').first().json.template_parts;

const intro_html = $('Render Intro').first().json.intro_html;
const posts_section_html = $('Render Posts Section').first().json.posts_section_html;
const events_section_html = $('Render Events Section').first().json.events_section_html;

// Inner body — injected into Mailchimp template via mc:edit="body"
const newsletter_html = [
  templates.header,
  intro_html,
  posts_section_html,
  events_section_html,
  templates.footer
].join('\n');

// Fetch the shell template from GitHub
const shellResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: 'https://raw.githubusercontent.com/krystian-kaczor/qagile-workflows/master/mailchimp-template.html',
  returnFullResponse: false
});

const shellHtml = typeof shellResponse === 'string' ? shellResponse : shellResponse.body;

// Find the mc:edit="body" div and replace everything between opening and closing tag.
// Use indexOf/lastIndexOf to avoid regex issues with deeply nested divs.
const openTag = '<div mc:edit="body">';
const start = shellHtml.indexOf(openTag);
if (start === -1) throw new Error('mc:edit="body" placeholder not found in shell template');

// Walk forward counting div depth to find the matching closing </div>
let depth = 0;
let i = start;
let end = -1;
while (i < shellHtml.length) {
  if (shellHtml.startsWith('<div', i)) depth++;
  else if (shellHtml.startsWith('</div>', i)) {
    depth--;
    if (depth === 0) { end = i + 6; break; }
  }
  i++;
}
if (end === -1) throw new Error('Could not find closing </div> for mc:edit="body"');

const rendered_html = shellHtml.slice(0, start) +
  openTag + newsletter_html + '</div>' +
  shellHtml.slice(end);

return [{ json: { newsletter_html, rendered_html } }];

function renderEvents(events, templateItem) {
  if (!Array.isArray(events) || events.length === 0) {
    return '<p style="text-align:center;">Brak nadchodzących szkoleń.</p>';
  }
  return events.map(event => {
    const title = event.json.title || 'Bez nazwy';
    const startDate = event.json.startDate || event.start_date || '';
    const location = event.json.location || '';
    const link = event.json.link || '';
    const isOnline = location.toLowerCase().includes('online');
    const icon = isOnline ? '<span style="color:#243760;">💻</span>' : '<span style="color:#243760;">🏢</span>';
    return templateItem
      .replace(/\{\{icon\}\}/g, icon)
      .replace(/\{\{link\}\}/g, link)
      .replace(/\{\{event_title\}\}/g, title)
      .replace(/\{\{start_date\}\}/g, startDate)
      .replace(/\{\{location\}\}/g, location);
  }).join('\n');
}

const templates = $('Merge Templates').first().json.template_parts;
const events = $('Call Get Upcoming Events').first().json.Events || [];

const events_section_html = templates.events_section.replace('{{events_html}}', renderEvents(events, templates.single_event));

return [{ json: { events_section_html } }];

function renderPosts(posts, templateItem) {
  if (!Array.isArray(posts) || posts.length === 0) {
    return '<p style="text-align:center;">Brak nowych artykułów.</p>';
  }
  return posts.map(post => {
    const title = post.title || 'Bez tytułu';
    const excerpt = post.excerpt || '';
    const url = post.url || '#';
    const image = post.image || post.image_url || 'https://placehold.co/560x200?text=QAgile';
    return templateItem
      .replace(/\{\{title\}\}/g, title)
      .replace(/\{\{excerpt\}\}/g, excerpt)
      .replace(/\{\{url\}\}/g, url)
      .replace(/\{\{image_url\}\}/g, image);
  }).join('\n');
}

const templates = $('Merge Templates').first().json.template_parts;
const posts = $('Call Get Recent Posts').first().json.blogPosts || [];
const limited = Array.isArray(posts) ? posts.slice(0, 4) : [];

const posts_section_html = templates.posts_section.replace('{{posts_html}}', renderPosts(limited, templates.single_post));

return [{ json: { posts_section_html } }];

const templates = $('Merge Templates').first().json.template_parts;

const now = new Date();
const monthName = now.toLocaleString('pl-PL', { month: 'long' });
const monthNameCapital = monthName.charAt(0).toUpperCase() + monthName.slice(1);
const year = now.getFullYear();

const intro_header = `${monthNameCapital} ${year} — Nowe Szkolenia i Artykuły`;
const intro_text = `Witaj w ${monthName}owym wydaniu newslettera QAgile! Przygotowaliśmy dla Ciebie świeże artykuły i aktualne terminy szkoleń Scrum.org oraz Kanban University.`;

const intro_html = templates.intro
  .replace(/\{\{intro_header\}\}/g, intro_header)
  .replace(/\{\{intro_text\}\}/g, intro_text);

return [{ json: { intro_html } }];

const newsletter = $('Assemble Newsletter').first().json;
const sentDate = new Date().toISOString().split('T')[0];
const now = new Date();
const newsletterMonth = `${now.toLocaleString('pl-PL', {month: 'long'})} ${now.getFullYear()}`;

return [{
  json: {
    sentDate: sentDate,
    newsletterMonth: newsletterMonth,
    htmlLength: (newsletter.newsletter_html || '').length
  }
}];

const newsletter = $input.first().json;
const now = new Date();
const opts = { timeZone: 'Europe/Warsaw', year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit', hour12: false };
const parts = new Intl.DateTimeFormat('pl-PL', opts).formatToParts(now);
const get = (type) => parts.find(p => p.type === type).value;
const fileName = `newsletter-${get('year')}-${get('month')}-${get('day')}-${get('hour')}${get('minute')}.html`;

// Use full rendered HTML (shell + body) for the saved file
const htmlContent = newsletter.rendered_html || newsletter.newsletter_html;
const htmlBuffer = Buffer.from(htmlContent, 'utf8');

return [{
  json: { fileName },
  binary: {
    data: await this.helpers.prepareBinaryData(htmlBuffer, fileName, 'text/html')
  }
}];

